import io.grpc.*;
import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class FileUploadServer {

    private Server server;

    private void start() throws IOException {
        int port = 50051;
        this.server = ServerBuilder.forPort(port)
                .addService(new FileUploadServiceImpl())
                .build()
                .start();
        System.out.println("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            try {
                FileUploadServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
            System.err.println("*** server shut down");
        }));
    }

    private void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(5, TimeUnit.SECONDS);
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        final FileUploadServer server = new FileUploadServer();
        server.start();
        server.blockUntilShutdown();
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }
}

class FileUploadServiceImpl extends FileUploadServiceGrpc.FileUploadServiceImplBase {

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadStatus> responseObserver) {
        return new StreamObserver<FileChunk>() {
            long totalBytesReceived = 0;

            @Override
            public void onNext(FileChunk fileChunk) {
                // Process the file chunk
                byte[] data = fileChunk.getData().toByteArray();
                totalBytesReceived += data.length;
                System.out.println("Received " + data.length + " bytes");
                // Acknowledge receipt of the chunk
                responseObserver.onNext(UploadStatus.newBuilder()
                        .setStatus("Chunk received")
                        .setBytesProcessed(totalBytesReceived)
                        .build());
            }

            @Override
            public void onError(Throwable throwable) {
                throwable.printStackTrace();
                responseObserver.onError(throwable);
            }

            @Override
            public void onCompleted() {
                System.out.println("File upload completed. Total bytes: " + totalBytesReceived);
                responseObserver.onNext(UploadStatus.newBuilder()
                        .setStatus("File upload complete")
                        .setBytesProcessed(totalBytesReceived)
                        .build());
                responseObserver.onCompleted();
            }
        };
    }
}